function ModelHeroSpirit:InitStr()
    local configRef = GameTable.CharacterConfigRef

    -- 英雄献祭参数
    self._xianjiData = {}
    self._xianjiData.race = {}
    local heroSacrificeRace = configRef["heroSacrificeRace"]
    heroSacrificeRace = string.split(heroSacrificeRace, ",")
    --for i,v in ipairs(heroSacrificeRace) do table.insert(self._xianjiData.race,tonumber(v)) end
    for i, v in ipairs(heroSacrificeRace) do
        local race = tonumber(v)
        self._xianjiData.race[race] = race
    end

    -- 英雄融合参数
    self._rongheData = {}
    self._rongheData.race = {}
    local heroFuseRace = configRef["heroFuseRace"]
    heroFuseRace = string.split(heroFuseRace, ",")
    --for i,v in ipairs(heroFuseRace) do table.insert(self._rongheData.race,tonumber(v)) end
    for i, v in ipairs(heroFuseRace) do
        local race = tonumber(v)
        self._rongheData.race[race] = race
    end

    -- 英雄转换参数
    self._zhuanhuanData = {}
    self._zhuanhuanData.race = {}
    local heroChangeRace = configRef["heroChangeRace"]
    heroChangeRace = string.split(heroChangeRace, ",")
    --for i,v in ipairs(heroChangeRace) do table.insert(self._zhuanhuanData.race,tonumber(v)) end
    for i, v in ipairs(heroChangeRace) do
        local race = tonumber(v)
        self._zhuanhuanData.race[race] = race
    end
    self._zhuanhuanData.star = {}
    local heroChangeStar = configRef["heroChangeStar"]
    heroChangeStar = string.split(heroChangeStar, ";")
    for i, v in ipairs(heroChangeStar) do
        v = string.split(v, ",")
        local temp = string.split(v[2], "=")
        table.insert(self._zhuanhuanData.star, { heroStar = tonumber(v[1]), refId = tonumber(temp[2]), num = tonumber(temp[3]) })
    end

    -- 英雄置换参数
    self._zhihuanData = {}
    self._zhihuanData.race = {}
    local heroDiSplaceRace = configRef["heroDiSplaceRace"]
    heroDiSplaceRace = string.split(heroDiSplaceRace, ",")
    --for i,v in ipairs(heroDiSplaceRace) do table.insert(self._zhihuanData.race,tonumber(v)) end
    for i, v in ipairs(heroDiSplaceRace) do
        local race = tonumber(v)
        self._zhihuanData.race[race] = race
    end
    self._zhihuanData.star = {}
    local heroDiSplaceStar = configRef["heroDiSplaceStar"]
    heroDiSplaceStar = string.split(heroDiSplaceStar, ";")
    for i, v in ipairs(heroDiSplaceStar) do
        v = string.split(v, ":")
        local need = string.split(v[3], "=")
        local data = { heroStar = tonumber(v[1]), heroNum = tonumber(v[2]), refId = tonumber(need[2]), num = tonumber(need[3]) }
        table.insert(self._zhihuanData.star, data)
    end

    -- 英雄重生参数
    self._chongshengData = {}
    self._chongshengData.race = {}
    local heroLevelRebornRace = configRef["heroLevelRebornRace"]
    heroLevelRebornRace = string.split(heroLevelRebornRace, ",")
    --for i,v in ipairs(heroLevelRebornRace) do table.insert(self._chongshengData.race,tonumber(v)) end
    for i, v in ipairs(heroLevelRebornRace) do
        local race = tonumber(v)
        self._chongshengData.race[race] = race
    end
    self._chongshengData.rebornNeed = {}
    local heroLevelRebornNeed = configRef["heroLevelRebornNeed"]
    heroLevelRebornNeed = string.split(heroLevelRebornNeed, ";")
    for i, v in ipairs(heroLevelRebornNeed) do
        v = string.split(v, "=")
        table.insert(self._chongshengData.rebornNeed, { refId = tonumber(v[2]), num = tonumber(v[3]) })
    end

    -- 英雄回退参数
    self._huituiData = {}
    self._huituiData.race = {}
    local heroReturnRace = configRef["heroReturnRace"]
    heroReturnRace = string.split(heroReturnRace, ",")
    --for i,v in ipairs(heroReturnRace) do table.insert(self._huituiData.race,tonumber(v)) end
    for i, v in ipairs(heroReturnRace) do
        local race = tonumber(v)
        self._huituiData.race[race] = race
    end

    self._zhuanshengData = {}
    self._zhuanshengData.race = {}
    local heroReturnRace1 = configRef["heroReturnRace1"]
    heroReturnRace1 = string.split(heroReturnRace1, ",")
    --for i,v in ipairs(heroReturnRace1) do table.insert(self._zhuanshengData.race,tonumber(v)) end
    for i, v in ipairs(heroReturnRace1) do
        local race = tonumber(v)
        self._zhuanshengData.race[race] = race
    end

    local heroReturnKeyList = {}
    self._heroReturnRef = {}
    local star, type, returnStar, race
    for k, v in pairs(GameTable.CharacterReturnRef) do
        type = v.type
        race = tonumber(v.race)
        star = v.star
        returnStar = v.returnStar

        local data = {}
        data.race = race
        data.star = star
        data.type = type
        data.returnStar = returnStar
        local need = string.split(v.need, "=")
        data.need = { itemType = tonumber(need[1]), refId = tonumber(need[2]), num = tonumber(need[3]) }

        local fixRewardList = {}
        local fixReward = string.split(v.fixReward, ",")
        for _i, _v in ipairs(fixReward) do
            _v = string.split(_v, "=")
            table.insert(fixRewardList, { itemType = tonumber(_v[1]), refId = tonumber(_v[2]), num = tonumber(_v[3]) })
        end
        data.fixReward = fixRewardList

        data.getNoumenonNum = v.getNoumenonNum

        local coreMaterialsList = {}
        local coreMaterials = string.split(v.coreMaterials, ",")
        for _i, _v in ipairs(coreMaterials) do
            _v = string.split(_v, "=")
            table.insert(coreMaterialsList, { itemType = tonumber(_v[1]), refId = tonumber(_v[2]), num = tonumber(_v[3]) })
        end
        data.coreMaterials = coreMaterialsList
        data.heroType = v.heroType or  0
        self._heroReturnRef[k] = data

        local typeInfo = heroReturnKeyList[type]
        if not typeInfo then
            typeInfo = {}
            heroReturnKeyList[type] = typeInfo
        end
        local raceInfo = typeInfo[race]
        if not raceInfo then
            raceInfo = {}
            typeInfo[race] = raceInfo
        end
        local starInfo = raceInfo[star]
        if not starInfo then
            starInfo = {}
            raceInfo[star] = starInfo
        end
        local returnStarInfo = starInfo[returnStar]
        if returnStarInfo then
            if LOG_INFO_ENABLED then
                printInfoN("======= 配置一致 refId:" .. k .. "，类型:" .. type .. "，星级:" .. star .. "，回退星级:" .. returnStar)
            end
        else
            starInfo[returnStar] = k
        end
    end
    self._heroReturnKeyList = heroReturnKeyList            -- 索引到refId

    self._heroUpStarLimit = {}
    local heroUpStarLimit = configRef["heroUpStarLimit"]
    heroUpStarLimit = string.split(heroUpStarLimit, ",")
    for i, v in ipairs(heroUpStarLimit) do
        v = string.split(v, "=")
        local star, lv = tonumber(v[1]), tonumber(v[2])
        self._heroUpStarLimit[star] = lv
    end
end

