-- 聚灵殿
function ModelHeroSpirit:GetHeroSortListBySpirit(heroTypeList, page, needList, tabIndex)
    local heroList = gModelHero:GetHeroList()
    if not heroList then
        return {}
    end
    local sortHeroList = {}
    for k, v in pairs(heroList) do
        local star, lv = v._star, v._level
        if not heroTypeList then
            if page ~= 3 and page ~= 4 then
                if page == 1 then
                    if needList then
                        if star <= needList then
                            table.insert(sortHeroList, v)
                        end
                    else
                        table.insert(sortHeroList, v)
                    end
                else
                    table.insert(sortHeroList, v)
                end
            else
                if page == 3 then
                    if needList[star] then
                        table.insert(sortHeroList, v)
                    end
                elseif page == 4 then
                    if tabIndex == 1 then
                        if lv >= needList then
                            table.insert(sortHeroList, v)
                        end
                    else
                        if star > needList then
                            table.insert(sortHeroList, v)
                        end
                    end
                end
            end
        else
            local race = gModelHero:GetHeroType(v._refId)
            if heroTypeList[race] then
                if page ~= 3 and page ~= 4 then
                    if page == 1 then
                        if needList then
                            if star <= needList then
                                table.insert(sortHeroList, v)
                            end
                        else
                            table.insert(sortHeroList, v)
                        end
                    else
                        table.insert(sortHeroList, v)
                    end
                else
                    if page == 3 then
                        if needList[star] then
                            table.insert(sortHeroList, v)
                        end
                    elseif page == 4 then
                        if tabIndex == 1 then
                            if lv >= needList then
                                table.insert(sortHeroList, v)
                            end
                        else
                            if star > needList then
                                table.insert(sortHeroList, v)
                            end
                        end
                    end
                end
            end
        end
    end
    table.sort(sortHeroList, function(hero1, hero2)
        local status1, status2 = hero1:GetStatus(), hero2:GetStatus()
        if status1 == status2 and status1 == 0 then
            local star1, star2 = hero1:GetStar(), hero2:GetStar()
            if star1 == star2 then
                local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
                if lv1 == lv2 then
                    --[[					local pow1,pow2 = hero1:GetPower(),hero2:GetPower()
                                        if pow1 == pow2 then
                                            local refId1,refId2 = hero1:GetRefId(),hero2:GetRefId()
                                            if refId1 == refId2 then
                                                local id1,id2 = hero1:GetId(),hero2:GetId()
                                                return id1 > id2
                                            else
                                                return refId1 < refId2
                                            end
                                        else
                                            return pow1 < pow2
                                        end]]

                    local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
                    if refId1 == refId2 then
                        local pow1, pow2 = hero1:GetPower(), hero2:GetPower()
                        if pow1 == pow2 then
                            local id1, id2 = hero1:GetId(), hero2:GetId()
                            return id1 > id2
                        else
                            return pow1 < pow2
                        end
                    else
                        return refId1 < refId2
                    end
                else
                    return lv1 < lv2
                end
            else
                return star1 < star2
            end
            --[[		elseif (not status1) and (not status2) then
                        local combat1,combat2 = hero1:GetCombatStatus(),hero2:GetCombatStatus()
                        if combat1 == combat2 and combat1 == 0 then
                            local resonance1,resonance2 = hero1:GetResonanceStatus(),hero2:GetResonanceStatus()
                            if resonance1 == resonance2 and resonance1 == 0 then
                                local lock1,lock2 = hero1:GetLockStatus(),hero2:GetLockStatus()
                                return lock1 < lock2
                            else
                                return resonance1 < resonance2
                            end
                        else
                            return combat1 < combat2
                        end]]
        else
            return status1 < status2
        end
    end)
    return sortHeroList
end

