-- 聚灵殿 献祭
function ModelHeroSpirit:GetHeroSortListBySpiritPage1(heroTypeList, needList)
    local heroList = gModelHero:GetHeroList()
    if not heroList then
        return {}
    end
    local sortHeroList = {}
    for k, v in pairs(heroList) do
        local refId, star = v:GetRefId(), v:GetStar()
        if heroTypeList then
            local ref = gModelHero:GetHeroRef(refId)
            if ref then
                local raceType = ref.raceType
                if heroTypeList[raceType] then
                    --local starId = gModelHero:GetStarId(starType,star)
                    --local starRef = gModelHero:GetHeroStarById(starId)
                    local starRef = gModelHero:GetStarRefById(v:GetId())

                    local sacrifice = starRef.sacrifice
                    if sacrifice == 1 then
                        if needList then
                            if star <= needList then
                                table.insert(sortHeroList, v)
                            end
                        else
                            table.insert(sortHeroList, v)
                        end
                    end
                end
            else
                printInfoNR("========== 没有找到对应的refId数据 ：" .. refId)
            end
        else
            table.insert(sortHeroList, v)
        end
    end
    table.sort(sortHeroList, function(hero1, hero2)
        local status1, status2 = hero1:GetStatus(), hero2:GetStatus()
        if status1 == status2 and status1 == 0 then
            local star1, star2 = hero1:GetStar(), hero2:GetStar()
            if star1 == star2 then
                local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
                if lv1 == lv2 then
                    --[[					local pow1,pow2 = hero1:GetPower(),hero2:GetPower()
                                        if pow1 == pow2 then
                                            local refId1,refId2 = hero1:GetRefId(),hero2:GetRefId()
                                            if refId1 == refId2 then
                                                local id1,id2 = hero1:GetId(),hero2:GetId()
                                                return id1 > id2
                                            else
                                                return refId1 < refId2
                                            end
                                        else
                                            return pow1 < pow2
                                        end]]
                    local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
                    if refId1 == refId2 then
                        local pow1, pow2 = hero1:GetPower(), hero2:GetPower()
                        if pow1 == pow2 then
                            local id1, id2 = hero1:GetId(), hero2:GetId()
                            return id1 > id2
                        else
                            return pow1 < pow2
                        end
                    else
                        return refId1 < refId2
                    end
                else
                    return lv1 < lv2
                end
            else
                return star1 < star2
            end
        elseif status1 == status2 and status1 == 1 then
            local combat1, combat2 = hero1:GetCombatStatus(), hero2:GetCombatStatus()
            if combat1 ~= combat2 then
                return combat1 > combat2
            else
                local lock1, lock2 = hero1:GetLockStatus(), hero2:GetLockStatus()
                if lock1 ~= lock2 then
                    return lock1 > lock2
                else
                    local resonance1, resonance2 = hero1:GetResonanceStatus(), hero2:GetResonanceStatus()
                    if resonance1 ~= resonance2 then
                        return resonance1 > resonance2
                    else
                        local star1, star2 = hero1:GetStar(), hero2:GetStar()
                        if star1 == star2 then
                            local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
                            if lv1 == lv2 then
                                --[[								local pow1,pow2 = hero1:GetPower(),hero2:GetPower()
                                                                if pow1 == pow2 then
                                                                    local refId1,refId2 = hero1:GetRefId(),hero2:GetRefId()
                                                                    if refId1 == refId2 then
                                                                        local id1,id2 = hero1:GetId(),hero2:GetId()
                                                                        return id1 > id2
                                                                    else
                                                                        return refId1 < refId2
                                                                    end
                                                                else
                                                                    return pow1 < pow2
                                                                end]]
                                local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
                                if refId1 == refId2 then
                                    local pow1, pow2 = hero1:GetPower(), hero2:GetPower()
                                    if pow1 == pow2 then
                                        local id1, id2 = hero1:GetId(), hero2:GetId()
                                        return id1 > id2
                                    else
                                        return pow1 < pow2
                                    end
                                else
                                    return refId1 < refId2
                                end
                            else
                                return lv1 < lv2
                            end
                        else
                            return star1 < star2
                        end
                    end
                end
            end
        else
            return status1 < status2
        end
    end)
    return sortHeroList
end

-- 聚灵殿 融合
function ModelHeroSpirit:GetHeroSortListBySpiritPage2(heroTypeList)
    local sortHeroList = self:GetHeroUpStarStatus(heroTypeList)
    table.sort(sortHeroList, function(hero1, hero2)
        local isFuse1, isFuse2 = hero1:GetFuseStatus(), hero2:GetFuseStatus()
        local upStar1, upStar2 = hero1:GetUpStar(), hero2:GetUpStar()
        local star1, star2 = hero1:GetStar(), hero2:GetStar()
        local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
        local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
        local pow1, pow2 = hero1:GetPower(), hero2:GetPower()
        local id1, id2 = hero1:GetId(), hero2:GetId()
        if isFuse1 == isFuse2 then
            if upStar1 == upStar2 and upStar1 == 1 then
                if star1 == star2 then
                    if lv1 == lv2 then
                        if refId1 == refId2 then
                            if pow1 == pow2 then
                                return id1 > id2
                            else
                                return pow1 < pow2
                            end
                        else
                            return refId1 < refId2
                        end
                    else
                        return lv1 > lv2
                    end
                else
                    return star1 > star2
                end
            else
                if upStar1 ~= upStar2 then
                    return upStar1 < upStar2
                else
                    if star1 == star2 then
                        if lv1 == lv2 then
                            if refId1 == refId2 then
                                if pow1 == pow2 then
                                    return id1 > id2
                                else
                                    return pow1 < pow2
                                end
                            else
                                return refId1 < refId2
                            end
                        else
                            return lv1 > lv2
                        end
                    else
                        return star1 > star2
                    end
                end
            end
        else
            if upStar1 == upStar2 and upStar1 == 1 then
                return isFuse1 > isFuse2
            else
                return upStar1 < upStar2
            end
        end
    end)
    return sortHeroList
end

function ModelHeroSpirit:GetHeroUpStarStatus(heroTypeList, status)
    local heroList = gModelHero:GetHeroList()
    if not heroList then
        return {}
    end
    local sortHeroList = {}
    local resonanceLevel = gModelResonance:GetResonanceLv()
    local getUpStarStatus = false
    local heroUpStarLimit = self:GetUpStarLimit()
    for k, v in pairs(heroList) do
        if getUpStarStatus then
            break
        end
        local refId = v._refId
        local ref = gModelHero:GetHeroRef(refId)
        if ref then
            local goNext = true
            local raceType = ref.raceType
            if heroTypeList then
                goNext = heroTypeList[raceType] ~= nil
            end

            --if v._refId == 2702 and v._star == 8 then
            --    printInfoN2("--","--")
            --end


            if goNext then
                local id, star = v._id, v._star
                local upStarInfo = gModelHero:GetUpStarHeroInfoByHeroRefIdAndStar(refId, star)
                if upStarInfo then
                    local upStar = upStarInfo.upStar
                    if upStar ~= 0 then
                        local nextStar = star + 1
                        local data = {}
                        local fuse1, fuse2, fuse3 = true, true, true
                        local upStarAppoint, upStarRange, upStarItem = upStarInfo.upStarAppoint, upStarInfo.upStarRange, upStarInfo.upStarItem
                        local needRefId, needStar, needNum
                        for _i, _v in ipairs(upStarAppoint) do
                            if not fuse1 then
                                break
                            end
                            needRefId, needStar, needNum = _v.needRefId, _v.needStar, _v.needNum
                            local dataList = gModelHero:FilterHero(needRefId, needStar, nil, id, {}, needNum)
                            local haveNum = table.keysize(dataList)
                            local tempList = {}
                            local aaa = 0
                            for key, val in pairs(dataList) do
                                if aaa >= needNum then
                                    break
                                end
                                tempList[key] = val
                                aaa = aaa + 1
                            end
                            table.insert(data, tempList)
                            fuse1 = haveNum >= needNum
                        end
                
                        
                        if fuse1 then
                            local _condition = {}

                            for _i, _v in ipairs(upStarRange) do

                                local needRefId, needStar, needNum = _v.needRefId  ,_v.needStar , _v.needNum
                                _condition[needRefId] = _condition[needRefId] or {}
                                _condition[needRefId][needStar] = _condition[needRefId][needStar] or 0
                                _condition[needRefId][needStar] = needNum + _condition[needRefId][needStar]
                            end
                            
                            for _i, _v in ipairs(upStarRange) do
                                if not fuse2 then
                                    break
                                end

                                local needHeroRefId, needHeroStar  =  _v.needRefId,_v.needStar


                                needRefId, needStar, needNum = _v.needRefId, _v.needStar, _v.needNum
                                --local dataList, yinghunItemList = gModelHero:FilterHero(needRefId, needStar, needRefId, id, {}, needNum)

                                local dataList, yinghunItemList = gModelHero:FilterHero(needHeroRefId, needHeroStar, needHeroRefId, id, {})
                                local haveNum = table.keysize(dataList) + table.keysize(yinghunItemList)
                                local selNum = 0
                                for dataIndex, dataVal in ipairs(data) do
                                    for key, value in pairs(dataVal) do
                                        if dataList[key] then
                                            selNum = selNum + 1
                                        end
                                    end
                                end
                                haveNum = haveNum - selNum

                                local checkNeedNum = 0
                                if needHeroRefId == 0 then
                                    for kcondition, condition in pairs(_condition) do
                                        checkNeedNum = checkNeedNum + checknumber(condition[needHeroStar])
                                    end

                                elseif needHeroRefId == 6 then
                                    -- 计算三系列的消耗
                                    -- 1   2  3
                                    for kcondition, condition in pairs(_condition) do
                                        if k ==1 or k == 2 or k == 3 then
                                            checkNeedNum = checkNeedNum + checknumber(condition[needHeroStar])
                                        end
                                    end
                                elseif needHeroRefId == 7 then
                                    --计算光暗 两系的消耗  4  5 
                                    for kcondition, condition in pairs(_condition) do
                                        if kcondition ==4 or kcondition == 5  then
                                            checkNeedNum = checkNeedNum + checknumber(condition[needStar])
                                        end
                                    end

                                else
                                    -- 只需计算0 和自己本身的消耗
                                    for kcondition, condition in pairs(_condition) do
                                        if kcondition ==0 or kcondition== needHeroRefId then
                                            checkNeedNum = checkNeedNum + checknumber(condition[needHeroStar])
                                        end
                                    end
                                end




                                fuse2 = haveNum >= checkNeedNum
                                
                            end
                            if fuse2 then
                                local itemRefId, num
                                for _i, _v in ipairs(upStarItem) do
                                    if not fuse3 then
                                        break
                                    end
                                    itemRefId, num = _v.itemId, _v.itemNum
                                    local haveNum = gModelItem:GetNumByRefId(itemRefId)
                                    fuse3 = haveNum >= num
                                end
                            end
                        end
                        local temp = 0
                        local fuse = fuse1 and fuse2 and fuse3
                        if fuse then
                            local maxStar = ref.maxStar
                            local upStarLimit
                            if maxStar < nextStar then
                                upStarLimit = heroUpStarLimit[star]
                            else
                                upStarLimit = heroUpStarLimit[nextStar]
                            end
                            local isAdd = true
                            if upStarLimit then
                                isAdd = upStarLimit <= resonanceLevel
                            end
                            if isAdd then
                                temp = 1
                            end
                        end
                        if status and temp == 1 then
                            getUpStarStatus = true
                        end
                        v:SetFuseStatus(temp)
                        table.insert(sortHeroList, v)
                    end
                    v:SetUpStar(upStar)
                end
            else
                printInfoNR("========== 没有找到对应的refId数据 ：" .. refId)
            end
        end
    end
    if status then
        return getUpStarStatus
    else
        return sortHeroList
    end
end

