        LogError("没有设置回调函数或英雄Id")
        return
    end
    local wndId = 50906
    func = func or function()
        local pos = gModelResonance:GetResonanceHeroPos(heroId)
        if pos then
            gModelResonance:OnResonanceHeroReq(heroId, pos, 2)
        end
    end

    local resonanceTime = GameTable.LevelShareConfigRef["resonanceTime"]
    local subTime = gModelGrade:GetHeroResonanceEffectValue()
    resonanceTime = resonanceTime - subTime
    local hour = math.floor(resonanceTime / 3600)
    gModelGeneral:OpenUIOrdinTips({ refId = wndId, func = func, para = { hour } })

    --local openFunc = function() GF.OpenWnd("UIOrdinTip",{refId = wndId,func = func}) end
    --gModelGeneral:ShowUIOrdinTip(wndId,func,openFunc)
end

