function ModelHeroSpirit:ClearUpStarSelHeroList()
    self._upStarSelHero = {}
end

function ModelHeroSpirit:SetSelHeroId(id)
    local selHeroList = self._upStarSelHero
    if not selHeroList then
        selHeroList = {}
        self._upStarSelHero = selHeroList
    end
    local b = self:IsHeroIdSel(id)
    if b then
        selHeroList[id] = nil
    else
        selHeroList[id] = id
    end
end

-- true:选中了 false:没选中
function ModelHeroSpirit:IsHeroIdSel(id)
    local selHeroList = self._upStarSelHero
    if table.isempty(selHeroList) then
        return false
    end
    if selHeroList[id] then
        return true
    else
        return false
    end
end

function ModelHeroSpirit:FilterHero(hRefId, hStar, hType, selHeroId, selHeroList, needNum)
    local filterList = {}
    -- 英雄筛选
    local heroList = gModelHero:GetHeroList()
    if heroList then
        for k, v in pairs(heroList) do
            local data
            local id = v:GetId()
            local heroStatus = v:GetStatus()
            if id ~= selHeroId and heroStatus == 0 then
                if hType then
                    local star = v:GetStar()
                    if hType == 0 and star == hStar then
                        if selHeroList[id] then
                            data = v
                        else
                            if not self:IsHeroIdSel(id) then
                                data = v
                            end
                        end
                    else
                        local refId = v:GetRefId()
                        local heroRef = gModelHero:GetHeroRef(refId)
                        if heroRef then
                            local rType = heroRef.raceType
                            if rType == hType and star == hStar then
                                if selHeroList[id] then
                                    data = v
                                else
                                    if not self:IsHeroIdSel(id) then
                                        data = v
                                    end
                                end
                            end
                        end
                    end
                else
                    local refId = v:GetRefId()
                    local star = v:GetStar()
                    if refId == hRefId and star == hStar then
                        if selHeroList[id] then
                            data = v
                        else
                            if not self:IsHeroIdSel(id) then
                                data = v
                            end
                        end
                    end
                end
            end
            if data then
                filterList[k] = data
            end
        end
    end
    local serHeroRace
    if selHeroId then
        local refId = gModelHero:GetRefIdById(selHeroId)
        local ref = gModelHero:GetHeroRef(refId)
        if ref then
            serHeroRace = ref.raceType
        end
    end
    local itemList = {}
    if hType then
        -- 英魂筛选(道具)
        local bagYingHunList = gModelItem:GetBagYingHunList()
        for k, v in pairs(bagYingHunList) do
            local itemRefData = gModelItem:GetYingHunRefByRefId(k)
            if itemRefData then
                local isIns = false
                local refRace, refStar = itemRefData.race, itemRefData.star
                if serHeroRace and serHeroRace == refRace and refStar == hStar then
                    isIns = true
                elseif refRace == 0 and refStar == hStar then
                    isIns = true
                elseif refRace == hType and refStar == hStar then
                    isIns = true
                elseif refStar == hStar then
                    local other = ModelItem.RaceTypeList[refRace]
                    isIns = other and other[hType] or false
                end
                if isIns then
                    local itemStruct = gModelItem:GetItemServerDataByRefId(k)
                    if itemStruct then
                        local num = itemStruct._num
                        for i = 1, num do
                            if needNum and needNum < i then
                                break
                            end
                            local key = "itemRace_" .. refRace .. "_" .. i
                            itemList[key] = itemStruct
                        end
                    end
                end
            end
        end
    end
    return filterList, itemList
end

function ModelHeroSpirit:CheckIsCanUpStar(heroRefId, star, id)
    local fuse = false
    local upStarInfo = gModelHero:GetUpStarHeroInfoByHeroRefIdAndStar(heroRefId, star)
    if upStarInfo then
        local heroUpStarLimit = gModelHeroSpirit:GetUpStarLimit()
        local selHeroList = {}
        local fuse1, fuse2, fuse3 = true, true, true
        local upStarAppoint, upStarRange, upStarItem = upStarInfo.upStarAppoint, upStarInfo.upStarRange, upStarInfo.upStarItem
        for i, v in ipairs(upStarAppoint) do
            if not fuse1 then
                break
            end
            local needRefId, needStar, needNum = v.needRefId, v.needStar, v.needNum
            local dataList = self:FilterHero(needRefId, needStar, nil, id, {}, needNum)
            local haveNum = table.keysize(dataList)
            local tempList = {}
            local aaa = 0
            for key, val in pairs(dataList) do
                if aaa >= needNum then
                    break
                end
                tempList[key] = val
                aaa = aaa + 1
            end
            table.insert(selHeroList, tempList)
            fuse1 = haveNum >= needNum
        end
        for i, v in ipairs(upStarRange) do
            if not fuse2 then
                break
            end
            local needRefId, needStar, needNum = v.needRefId, v.needStar, v.needNum
            local dataList, yinghunItemList = self:FilterHero(needRefId, needStar, needRefId, id, {}, needNum)
            local haveNum = table.keysize(dataList) + table.keysize(yinghunItemList)
            local selNum = 0
            for dataIndex, dataVal in ipairs(selHeroList) do
                for key, value in pairs(dataVal) do
                    if dataList[key] then
                        selNum = selNum + 1
                    end
                end
            end
            haveNum = haveNum - selNum
            fuse2 = haveNum >= needNum
        end
        for i, v in ipairs(upStarItem) do
            if not fuse3 then
                break
            end
            local itemRefId, num = v.itemId, v.itemNum
            local haveNum = gModelItem:GetNumByRefId(itemRefId)
            fuse3 = haveNum >= num
        end
        fuse = fuse1 and fuse2 and fuse3
        if heroUpStarLimit then
            local maxStar = gModelHero:GetMaxStarByRefId(heroRefId)
            local upStarLimit
            local nextStar = star + 1
            if maxStar < nextStar then
                upStarLimit = heroUpStarLimit[star]
            else
                upStarLimit = heroUpStarLimit[nextStar]
            end
            if upStarLimit then
                -- 魔镜等级小于限制等级，显示文字隐藏按钮
                local resonanceLevel = gModelResonance:GetResonanceLv()
                if resonanceLevel < upStarLimit then
                    fuse = false
                end
            end
        end
    end
    return fuse
end

-- 一键升星机制
function ModelHeroSpirit:CheckAutoUpStarHeroStatus()
    local status = false
    local isOpen = gModelFunctionOpen:CheckIsOpened(16200201)
    if not isOpen then
        return status
    end
    local heroStarList = gModelHero:GetStarHeroList()
    for idx, heroInfo in ipairs(heroStarList) do
        if status then
            break
        end
        local refId, star, id = heroInfo.refId, heroInfo.star, heroInfo.id
        status = self:CheckIsCanUpStar(refId, star, id)
    end
    return status
end

function ModelHeroSpirit:GetAutoUpStarHeroList()
    local resonanceLevel = gModelResonance:GetResonanceLv()
    local heroUpStarLimit = gModelHeroSpirit:GetUpStarLimit()
    local allSelHeroIdKeyList = {}
    local allSelItemIdKeyList = {}
    local allSelHeroList = {}
    local heroStarList, refIdNumList = gModelHero:GetStarHeroList()
    table.sort(heroStarList, function(a, b)
        local refIdA, refIdB = a.refId, b.refId
        local haveNumA, haveNumB = refIdNumList[refIdA] or 1, refIdNumList[refIdB] or 1
        if haveNumA ~= haveNumB then
            return haveNumA > haveNumB
        else
            local fightPowerA, fightPowerB = a.fightPower, b.fightPower
            if fightPowerA ~= fightPowerB then
                return fightPowerA > fightPowerB
            else
                return refIdA > refIdB
            end
        end
    end)
    local curSelRefId = nil
    local sortFunc = function(a, b)
        local refIdA, refIdB = a:GetRefId(), b:GetRefId()
        local isSameSelA = refIdA == curSelRefId and 1 or 0
        local isSameSelB = refIdB == curSelRefId and 1 or 0
        if isSameSelA ~= isSameSelB then
            return isSameSelA < isSameSelB
        else
            local haveNumA, haveNumB = refIdNumList[refIdA] or 1, refIdNumList[refIdB] or 1
            if haveNumA ~= haveNumB then
                return haveNumA < haveNumB
            else
                local fightPowerA, fightPowerB = a:GetPower(), b:GetPower()
                if fightPowerA ~= fightPowerB then
                    return fightPowerA < fightPowerB
                else
                    return refIdA < refIdB
                end
            end
        end
    end
    for idx, heroInfo in ipairs(heroStarList) do
        local refId, star = heroInfo.refId, heroInfo.star
        local upStarInfo = gModelHero:GetUpStarHeroInfoByHeroRefIdAndStar(refId, star)
        if upStarInfo then
            local id = heroInfo.id
            if not allSelHeroIdKeyList[id] then
                local tData = {}
                local appointedlist = {}
                local rangelist = {}
                local rangItemList = {}
                tData.appointedlist = appointedlist
                tData.rangelist = rangelist
                tData.rangItemList = rangItemList
                curSelRefId = refId
                local fuse1, fuse2, fuse3 = true, true, true
                local upStarAppoint, upStarRange, upStarItem = upStarInfo.upStarAppoint, upStarInfo.upStarRange, upStarInfo.upStarItem
                for index, refData in ipairs(upStarAppoint) do
                    local tAppointedList = {}
                    appointedlist[index] = tAppointedList
                    if not fuse1 then
                        break
                    end
                    local needRefId, needStar, needNum = refData.needRefId, refData.needStar, refData.needNum
                    local dataList = self:FilterHero(needRefId, needStar, nil, id, {}, needNum)
                    local num = 0
                    local filtrateList = {}
                    for k, v in pairs(dataList) do
                        local tId = v:GetId()
                        local heroStatus = v:GetStatus()
                        if not allSelHeroIdKeyList[tId] and heroStatus == 0 then
                            table.insert(filtrateList, v)
                            num = num + 1
                        end
                    end
                    if num > 0 then
                        table.sort(filtrateList, sortFunc)
                        local addNum = 0
                        for i, v in ipairs(filtrateList) do
                            if i > needNum then
                                break
                            end
                            local tId = v:GetId()
                            allSelHeroIdKeyList[tId] = tId
                            tAppointedList[tId] = tId
                            addNum = addNum + 1
                        end
                        fuse1 = addNum >= needNum
                    else
                        fuse1 = false
                    end
                end
                if fuse1 then
                    for index, refData in ipairs(upStarRange) do
                        local tRangelist = {}
                        rangelist[index] = tRangelist
                        if not fuse2 then
                            break
                        end
                        local needRefId, needStar, needNum = refData.needRefId, refData.needStar, refData.needNum
                        local dataList = self:FilterHero(needRefId, needStar, needRefId, id, {}, needNum)
                        local num = 0
                        local filtrateList = {}
                        for k, v in pairs(dataList) do
                            local tId = v:GetId()
                            local heroStatus = v:GetStatus()
                            if not allSelHeroIdKeyList[tId] and heroStatus == 0 then
                                table.insert(filtrateList, v)
                                num = num + 1
                            end
                        end
                        if num > 0 then
                            table.sort(filtrateList, sortFunc)
                            local addNum = 0
                            for i, v in ipairs(filtrateList) do
                                if i > needNum then
                                    break
                                end
                                local tId = v:GetId()
                                allSelHeroIdKeyList[tId] = tId
                                tRangelist[tId] = tId
                                addNum = addNum + 1
                            end
                            fuse2 = addNum >= needNum
                            if not fuse2 then
                                for k, v in pairs(tRangelist) do
                                    allSelHeroIdKeyList[k] = nil
                                end
                            end
                        else
                            fuse2 = false
                        end
                    end
                else
                    fuse2 = false
                end
                if fuse1 and fuse2 then
                    for index, refData in ipairs(upStarItem) do
                        local tRangItemList = {}
                        rangItemList[index] = tRangItemList
                        if not fuse3 then
                            break
                        end
                        local itemRefId, num = refData.itemId, refData.itemNum
                        local haveNum = gModelItem:GetNumByRefId(itemRefId)
                        local selItemNum = allSelItemIdKeyList[itemRefId] or 0
                        haveNum = haveNum - selItemNum
                        fuse3 = haveNum >= num
                        if fuse3 then
                            tRangItemList[itemRefId] = num
                            allSelItemIdKeyList[itemRefId] = selItemNum + num
                        end
                    end
                else
                    fuse3 = false
                end
                local fuse = fuse1 and fuse2 and fuse3
                if heroUpStarLimit and fuse then
                    local maxStar = gModelHero:GetMaxStarByRefId(refId)
                    local upStarLimit
                    local nextStar = star + 1
                    if maxStar < nextStar then
                        upStarLimit = heroUpStarLimit[star]
                    else
                        upStarLimit = heroUpStarLimit[nextStar]
                    end
                    if upStarLimit then
                        if resonanceLevel < upStarLimit then
                            fuse = false
                        end
                    end
                end
                if fuse then
                    tData.id = id
                    table.insert(allSelHeroList, tData)
                    allSelHeroIdKeyList[id] = id
                else
                    for i, v in ipairs(appointedlist) do
                        for key, val in pairs(v) do
                            allSelHeroIdKeyList[key] = nil
                        end
                    end
                    for i, v in ipairs(rangelist) do
                        for key, val in pairs(v) do
                            allSelHeroIdKeyList[key] = nil
                        end
                    end
                    for i, v in ipairs(rangItemList) do
                        for itemRefId, num in pairs(v) do
                            local selItemIdNum = allSelItemIdKeyList[itemRefId]
                            if selItemIdNum then
                                allSelItemIdKeyList[itemRefId] = selItemIdNum - num
                            end
                        end
                    end
                end
            end
        end
    end
    local len = #allSelHeroList
    local status = len > 0
    return allSelHeroList, status
end

-- 时光沙漏功能
function ModelHeroSpirit:GetHeroReturnRefId(returnType, race, star, returnStar)
    local heroReturnKeyList = self._heroReturnKeyList
    if heroReturnKeyList then
        local typeInfo = heroReturnKeyList[returnType] or {}
        local raceInfo = typeInfo[race] or {}
        local starInfo = raceInfo[star] or {}
        return starInfo[returnStar]
    end
end

function ModelHeroSpirit:UseItemReturnHeroRewardList(itemRefId, heroServerData)
    if not heroServerData then
        return {}
    end
    if not itemRefId then
        return {}
    end
    local itemInfo = gModelItem:GetTimeHourGlassInfoByRefId(itemRefId)
    if not itemInfo then
        return {}
    end
    local star = heroServerData.star
    local heroStar = itemInfo.heroStar
    if star ~= heroStar then
        return {}
    end
    local returnToStar = itemInfo.returnToStar
    local heroRefId = heroServerData.refId
    local lv = heroServerData.lv
    local id = heroServerData.id

    local heroRace = gModelHero:GetHeroType(heroRefId)
    if not heroRace then
        return {}
    end
    local returnRefId = self:GetHeroReturnRefId(ModelHeroSpirit.RETURN_TYPE_3, heroRace, heroStar, returnToStar)
    if not returnRefId then
        return {}
    end
    local returnRef = self:GetHeroReturnRefByRefId(returnRefId)
    if not returnRef then
        return {}
    end
    local fixReward = returnRef.fixReward
    local heroRef = gModelHero:GetHeroRef(heroRefId)
    if not heroRef then
        return {}
    end
    --local starType = heroRef.starType
    --local starId = gModelHero:GetStarId(starType,star)
    local starRef = gModelHero:GetStarRefById(id, star)
    if not starRef then
        return {}
    end
    --local retStarId = gModelHero:GetStarId(starType,returnToStar)
    local retStarRef = gModelHero:GetStarRefById(id, returnToStar)
    if not retStarRef then
        return {}
    end
    local returnPayList = {}
    local retMaxLevel = retStarRef.maxLevel
    if retMaxLevel <= lv then
        local keyList = {}
        local starAndLvList = gModelHero:GetPayItemNumByStarAndEndLv(id, retMaxLevel, lv, retMaxLevel, returnToStar)
        for i, v in ipairs(starAndLvList) do
            local info = keyList[v.refId] or 0
            keyList[v.refId] = info + v.num
        end
        local classType = heroRef.classType
        local sortHeroClassList = gModelHero:GetSortHeroClassRefListByClassType(classType)
        if sortHeroClassList then
            local grade = heroServerData.grade
            for i, v in ipairs(sortHeroClassList) do
                if grade > v.grade and lv >= v.needLevel and v.needStar == star then
                    local needItem = string.split(v.needItem, ",")
                    for idx, val in ipairs(needItem) do
                        val = string.split(val, "=")
                        local tRefId = tonumber(val[2])
                        local tNum = tonumber(val[3])
                        local info = keyList[tRefId] or 0
                        keyList[tRefId] = info + tNum
                    end
                end
            end
        end
        for k, v in pairs(keyList) do
            table.insert(returnPayList, {
                refId = k, num = v
            })
        end
    else
        returnPayList = gModelRune:GetRuneUpItemList(id, lv, returnToStar)
    end
    local returnPayKeyList = {}
    for i, v in ipairs(returnPayList) do
        returnPayKeyList[v.refId] = v.num
    end
    for i, v in ipairs(fixReward) do
        local refId = v.refId
        local tNum = returnPayKeyList[refId] or 0
        returnPayKeyList[refId] = tNum + v.num
    end
    local list = {}
    local itemList = {}
    for k, v in pairs(returnPayKeyList) do
        table.insert(itemList, {
            itemType = LItemTypeConst.TYPE_ITEM,
            itemId = k,
            itemNum = v
        })
    end
    table.sort(itemList, function(a, b)
        local orderA, orderB = gModelItem:GetItemOrderByRefId(a.refId), gModelItem:GetItemOrderByRefId(b.refId)
        return orderA < orderB
    end)
    table.insert(list, {
        itemType = LItemTypeConst.TYPE_HERO,
        itemId = heroRefId,
        itemNum = returnRef.getNoumenonNum,
        returnStar = returnRef.returnStar
    })
    for i, v in ipairs(itemList) do
        table.insert(list, v)
    end
    return list
end

function ModelHeroSpirit:GetReturnItemInfo(itemId, selHeroId)
    if not itemId or not selHeroId then
        return
    end
    local itemInfo = gModelItem:GetTimeHourGlassInfoByRefId(itemId)
    if not itemInfo then
        return
    end
    if not selHeroId then
        return
    end
    local serverData = gModelHero:GetHeroServerDataById(selHeroId)
    if not serverData then
        return
    end
    local heroRefId = serverData.refId
    local raceType = gModelHero:GetHeroType(heroRefId)
    if not raceType then
        return
    end
    local heroStar = itemInfo.heroStar
    local returnToStar = itemInfo.returnToStar
    if not heroStar or not returnToStar then
        return
    end
    local returnRefId = self:GetHeroReturnRefId(ModelHeroSpirit.RETURN_TYPE_3, raceType, heroStar, returnToStar)
    if not returnRefId then
        return
    end
    local returnRef = self:GetHeroReturnRefByRefId(returnRefId)
    if not returnRef then
        return
    end
    local need = returnRef.need or {}
    return need.refId, need.num
end

